array_filter(
			$flexible_shipping_rates,
			function ( $shipping_rate ) use ( $methods ) {
				return in_array( (int) $shipping_rate['id'], wp_parse_id_list( $methods ), true );
			}
		)

array_map(
			function ( $v ) {
				return str_getcsv( $v, self::get_csv_delimiter() );
			},
			file( $tmp_name )
		)

uasort(
			$conditions,
			function ( Condition $condition1, Condition $condition2 ) {
				return $condition1->get_priority() <=> $condition2->get_priority(); // phpcs:ignore.
			}
		)

array_filter(
			$rates,
			function ( $rate ) use ( $meta_key ) {
				if ( ! is_object( $rate ) || ! method_exists( $rate, 'get_meta_data' ) ) {

					return true;
				}

				return ! ( $rate->get_meta_data()[ $meta_key ] ?? false );
			}
		)

array_filter($loaders, function ($loader) {
                try {
                    // BIG HACK TO GET PRIVATE PROPERTY
                    $reflection = new \ReflectionClass($loader);
                    $property = $reflection->getProperty('loader_info');
                    $property->setAccessible(\true);
                    /** @var WPDesk_Composer_Loader_Info $inner_info */
                    $inner_info = $property->getValue($loader);
                    $plugin_info = $inner_info->get_plugin_info();
                    return basename($plugin_info->get_plugin_file_name()) !== basename($this->plugin_file);
                } catch (\Exception $e) {
                    return \true;
                }
            })

